function MoviePreview({
  movieInfo: { id, vote_average, title, backdrop_path, overview, poster_path },
}) {
  const [isModalVisible, setIsModalVisible] = useState(false);
  return (
    <li className="movie-preview" key={id}>
      {isModalVisible && (
        <Modal>
          <div className="movie-detail">
            <button
              className="close-modal-button"
              type="button"
              onClick={() => setIsModalVisible(false)}
            >
              <i className="material-icons">close</i>
            </button>
            <img
              className="backdrop-image"
              src={`https://image.tmdb.org/t/p/w1280${backdrop_path}`}
              alt={`${title}'s Poster`}
            />
            <p className="movie-synopsis">{overview}</p>
          </div>
        </Modal>
      )}
      <img
        className="movie-image"
        src={`https://image.tmdb.org/t/p/w342${poster_path}`}
        alt={`${title}'s Poster`}
      />
      <h4 className="movie-title" title={title}>
        {title}
      </h4>
      <div className="movie-specifications">
        <div className="movie-details">
          <i className="material-icons">star</i>
          <span className="movie-rating">
            <strong>{vote_average}</strong>
            /10
          </span>
        </div>
        <button
          className="info-button"
          type="button"
          title="info"
          onClick={() => setIsModalVisible(true)}
        >
          <i className="material-icons">info</i>
        </button>
      </div>
    </li>
  );
}

export default MoviePreview;

MoviePreview.propTypes = {
  movieInfo: PropTypes.shape({
    id: PropTypes.number,
    video: PropTypes.bool.isRequired,
    vote_count: PropTypes.number.isRequired,
    vote_average: PropTypes.number.isRequired,
    title: PropTypes.string.isRequired,
    release_date: PropTypes.string.isRequired,
    original_language: PropTypes.string.isRequired,
    original_title: PropTypes.string.isRequired,
    genre_ids: PropTypes.arrayOf(PropTypes.number).isRequired,
    backdrop_path: PropTypes.string.isRequired,
    adult: PropTypes.bool.isRequired,
    overview: PropTypes.string.isRequired,
    poster_path: PropTypes.string.isRequired,
    popularity: PropTypes.number.isRequired,
    media_type: PropTypes.string.isRequired,
  }).isRequired,
};
